ghtest\":\"#E9F1F5\",\"shadeDark\":\"#807E7C\",\"shadeBase\":\"#807E7C\",\"contrast\":\"#000\",\"alt\":\"#fff\"},\"fonts\":{\"ci\":{\"name\":\"Verdana\",\"family\":[\"Verdana\",\"sans-serif\"],\"src\":[],\"weight\":800},\"regular\":{\"name\":\"regular\",\"family\":[\"-apple-system\",\"BlinkMacSystemFont\",\"Segoe UI\",\"Roboto\",\"Helvetica\",\"Arial\",\"sans-serif\",\"Apple Color Emoji\",\"Segoe UI Emoji\", \"Segoe UI Symbol\"],\"src\":[],\"weight\":300},\"bold\":{\"name\":\"bold\",\"family\":[\"-apple-system\",\"BlinkMacSystemFont\",\"Segoe UI\",\"Roboto\",\"Helvetica\",\"Arial\",\"sans-serif\",\"Apple Color Emoji\",\"Segoe UI Emoji\", \"Segoe UI Symbol\"],\"src\":[],\"weight\":700}}},\"base\":\"https://www.wppodcast.fr/wp-content/plugins/podlove-web-player/web-player/\"}}]);\n                podlovePlayer(player, \"https://www.wppodcast.fr/wp-json/podlove-web-player/shortcode/publisher/1464\", \"https://www.wppodcast.fr/wp-json/podlove-web-player/shortcode/config/default/theme/default\").then(function() {\n                  player &amp;&amp; player.classList.remove(\"podlove-web-player-loading\");\n                });\n              });\n            \n            \n              .podlove-web-player.podlove-web-player-loading {\n                opacity: 0;\n              }\n            \n        \n\n\n<p>N&rsquo;oubliez pas que vous pouvez écouter les épisodes sur <a href=\"https://www.wppodcast.fr/pocketcasts/\" data-type=\"link\" data-id=\"https://www.wppodcast.fr/pocketcasts/\" target=\"_blank\" rel=\"noreferrer noopener\">Pocket Casts</a>, <a href=\"https://www.wppodcast.fr/spotify/\" data-type=\"link\" data-id=\"https://www.wppodcast.fr/spotify/\" target=\"_blank\" rel=\"noreferrer noopener\">Spotify</a>, et <a href=\"https://www.wppodcast.fr/apple/\" data-type=\"link\" data-id=\"https://www.wppodcast.fr/apple/\" target=\"_blank\" rel=\"noreferrer noopener\">Apple Podcasts</a> ou <a href=\"https://www.wppodcast.fr/feed/podcast/\" data-type=\"link\" data-id=\"https://www.wppodcast.fr/feed/podcast/\" target=\"_blank\" rel=\"noreferrer noopener\">vous abonner directement au flux</a>.</p>\n\n\n\n<span id=\"more-1464\"></span>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"transcripcion-del-programa\">Transcript de l&rsquo;épisode</h2>\n\n\n\n<p>Bonjour, je suis <a href=\"https://www.linkedin.com/in/patriciabt/\"><u>Patricia</u></a>, et vous écoutez <a href=\"https://www.wppodcast.fr/\"><u>WordPress Podcast</u></a>, le bulletin d&rsquo;information de la communauté WordPress. Ce programme est la traduction française de la <a href=\"https://www.wppodcast.es/\"><u>version originale en espagnol</u></a> par Javier Casares.</p>\n\n\n\n<p>Dans cet épisode, vous trouverez les <strong>informations du 22&nbsp;au 28 janvier 2024</strong>.</p>\n\n\n\n<p>Actuellement, nous dépendons tous de Meetup.com comme plateforme pour les événements de type meetups de la Communauté WordPress. Mais le coût pour la Communauté est de plus de 200 000 dollars par an pour maintenir ce service, ce qui est extrêmement cher pour ce qu’offre cette plateforme.</p>\n\n\n\n<p>C&rsquo;est pourquoi, il y a déjà quelques années, en 2019, un groupe de contributeurs a commencé à penser créer GatherPress, une extension pour WordPress qui permet la création et la gestion d&rsquo;événements et de leurs lieux ainsi que l’enregistrement des participations.</p>\n\n\n\n<p>L’extension est maintenant dans une phase fonctionnelle, ce qui a entraîné <a href=\"https://make.wordpress.org/community/2024/01/22/proposal-pilot-program-to-test-gatherpress-on-the-wordpress-org-network-as-a-meetup-alternative/\"><u>la proposition d&rsquo;un projet pilote</u></a> dans laquelle diverses communautés locales l&rsquo;utiliseraient pour la tester et l’améliorer et commencer à l&rsquo;envisager comme une plateforme majeure qui unifierait tous les utilisateurs et toutes les utilisatrices directement à partir de WordPress.org.</p>\n\n\n\n<p>Avantages et inconvénients ? Parmi les avantages, les données seraient dans les mains de la Communauté et non d&rsquo;une entreprise privée, l&rsquo;amélioration de l&rsquo;outil dépendrait de la Communauté et non d&rsquo;externes, et le projet étant open source, ceci permettrait de recevoir des améliorations et révisions de toutes parts. En outre, le coût actuel de Meetup.com pourrait être réinvesti dans les événements, et non dans une entreprise externe.</p>\n\n\n\n<p>Pour les inconvenients, ce serait presque un recommencement à zéro, car faire connaître les évènements dépendrait uniquement de la Communauté.</p>\n\n\n\n<p>Il s&rsquo;est déjà écoulé plusieurs mois depuis le Community Summit, et parmi toutes les discussions qui ont eu lieu lors des différentes réunions, <a href=\"https://make.wordpress.org/project/2024/01/24/proposal-updates-to-five-for-the-future-from-the-community-summit/\"><u>une liste de recommandations a été présentée</u></a> pour améliorer le programme « Five for the Future ». Ce projet au sein de WordPress encourage les entreprises à s’impliquer d&rsquo;une manière ou d’une autre.</p>\n\n\n\n<p>Parmi les propositions, nous retrouvons l&rsquo;amélioration des outils pour l&rsquo;accueil des nouveaux contributeurs et nouvelles contributrices, ainsi qu&rsquo;une meilleure communication entre celles et ceux qui décident de s&rsquo;impliquer dans une équipe.</p>\n\n\n\n<p>Une autre considération est également la manière dont les entreprises pourraient parrainer une tâche, un projet ou même des personnes spécifiques pour une période donnée, par exemple pour le lancement d’une nouvelle version de WordPress.</p>\n\n\n\n<p>Nous avons déjà la <a href=\"https://make.wordpress.org/core/2024/01/25/wordpress-6-4-3-rc1-is-now-available/\"><u>version candidate 1 de WordPress 6.4.3</u></a>, qui corrige 5 éléments de base et 16 de l&rsquo;éditeur.</p>\n\n\n\n<p>La version finale est prévue pour le mardi 30 janvier.</p>\n\n\n\n<p>L&rsquo;équipe <strong>Core</strong> a annoncé que l&rsquo;une des grandes nouveautés de WordPress 6.5 sera <a href=\"https://make.wordpress.org/core/2024/01/22/core-editor-improvement-robust-revisions-in-the-site-editor/\"><u>le système de révisions</u></a>, principalement en raison du changement significatif qu’il représente. Les tests sont déjà disponibles dans WordPress 6.4.2 avec Gutenberg 17.5.1.</p>\n\n\n\n<p>La mise à jour, en plus d&rsquo;offrir un nouveau design, fournit un système d&rsquo;information plus granulaire et un résumé des changements, ce qui induit qu&rsquo;on ne dépend pas exclusivement d&rsquo;une révision visuelle.</p>\n\n\n\n<p>Les changements seront paginés, et incluront également les modifications dans le Guide de styles.</p>\n\n\n\n<p>Sur le <strong>Developers&rsquo; blog</strong>, un article expliquant comment <a href=\"https://developer.wordpress.org/news/2024/01/22/building-dynamic-block-based-attachment-templates-in-themes/\"><u>améliorer les modèles liés aux fichiers joints</u></a> a été publié.</p>\n\n\n\n<p>En général, ces pages affichent une image ou une vidéo avec des éléments par défaut, et pas grand-chose à voir.</p>\n\n\n\n<p>L&rsquo;article suggère, par exemple, d&rsquo;améliorer la taille de l&rsquo;image et d&rsquo;inclure les données EXIF de la photo, données que nous ne trouverions probablement pas là où la photo est susceptible d&rsquo;être affichée.<br><br>L&rsquo;équipe <strong>Themes</strong> a reçu une <a href=\"https://meta.trac.wordpress.org/ticket/7406\"><u>demande de la part d&rsquo;auteur·es de thèmes importants</u></a> pour permettre la soumission de plus d&rsquo;un thème à la fois.</p>\n\n\n\n<p>Certaines personnes pensent que les auteur·es qui envoient habituellement des thèmes ne nécessitant que peu ou pas d&rsquo;examen, essentiellement parce qu&rsquo;ils le font bien, devraient avoir cette possibilité. Même dans ce cas, il ne leur serait pas permis d&rsquo;envoyer une centaine de thèmes, mais cela pourrait être limité à 2 ou 3 thèmes en attente.</p>\n\n\n\n<p>Pour l&rsquo;instant, la décision sur ce changement a été laissée entre les mains des représentant·es de l&rsquo;équipe, bien qu’il semble que la stratégie ne changera pas, étant donné le temps d&rsquo;approbation assez rapide, de l’ordre de quelques heures, même pour les thèmes basés sur les blocs.<br><br>L&rsquo;équipe <strong>Training</strong> a pour objectif de lancer le projet Learning Pathways (chemins d’apprentissage) d&rsquo;ici juillet 2024. Dans ce projet, les créateurs et créatrices de contenu de la communauté aident à apprendre quelque chose de spécifique au sein de l&rsquo;écosystème WordPress.</p>\n\n\n\n<p>Cependant, il semble que ce projet sera retardé en raison d&rsquo;<a href=\"https://make.wordpress.org/training/2024/01/22/discussion-trainings-contribution-to-the-6-5-release-and-beyond/\"><u>un manque de personnes contributrices</u></a>. Cela force une priorisation de la proposition, en se concentrant sur l&rsquo;identification des éléments minimaux nécessaires pour démarrer, pour ensuite développer ces éléments. Une proposition visant à améliorer l&rsquo;arrivée de nouvelles personnes contributrices sera également lancée.</p>\n\n\n\n<p>L&rsquo;équipe <strong>Community</strong> organise une présentation en ligne le 8 février, au cours de laquelle elle présentera <a href=\"https://make.wordpress.org/community/2024/01/29/community-team-training-12-wordcamp-budgeting-tips/\"><u>quelques conseils relatifs aux budgets pour les événements WordPress</u></a>, tels que les besoins, les standards.<br><br>Pour finir, ce podcast est distribué sous <a href=\"https://eupl.eu/1.2/fr/\">licence EUPL</a> ; vous trouverez tous les liens pour plus d&rsquo;informations sur <a href=\"https://www.wppodcast.fr/\"><u>WPPodcast.fr</u></a> où se trouve tout le contenu, également disponible en <a href=\"https://www.wppodcast.org/\"><u>anglais</u></a>, en <a href=\"https://www.wppodcast.es/\"><u>espagnol</u></a> et en <a href=\"https://www.wppodcast.cat/\"><u>catalan</u></a>.</p>\n\n\n\n<p>A la prochaine !</p>\n\n    \";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:4:\"type\";s:4:\"html\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"author\";a:1:{i:0;a:6:{s:4:\"data\";s:46:\"\n            \n                                \";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"name\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Patricia BT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:6:\"source\";a:1:{i:0;a:6:{s:4:\"data\";s:67:\"\n                    \n                            \n                \";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:27:\"http://www.w3.org/2005/Atom\";a:2:{s:2:\"id\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://www.wppodcast.fr/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"WP Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}i:2;a:6:{s:4:\"data\";s:57:\"\n    \n    \n    \n    \n    \n    \n    \n                \n    \";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:27:\"http://www.w3.org/2005/Atom\";a:8:{s:2:\"id\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://www.echodesplugins.li-an.fr/plugins/changement-de-lurl-du-flux-de-lecho-des-plugins/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:54:\"Changement de l’URL du flux de l’Écho des Plugins\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:4:\"type\";s:4:\"html\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\