INSERT INTO `wp_postmeta` VALUES (277,259,'_messages','a:22:{s:12:\"mail_sent_ok\";s:45:\"Merci pour votre message. Il a été envoyé.\";s:12:\"mail_sent_ng\";s:102:\"Une erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\";s:16:\"validation_error\";s:88:\"Un ou plusieurs champs contiennent une erreur. Veuillez vérifier et essayer à nouveau.\";s:4:\"spam\";s:102:\"Une erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\";s:12:\"accept_terms\";s:77:\"Vous devez accepter les termes et conditions avant d’envoyer votre message.\";s:16:\"invalid_required\";s:29:\"Veuillez renseigner ce champ.\";s:16:\"invalid_too_long\";s:34:\"Ce champ a une saisie trop longue.\";s:17:\"invalid_too_short\";s:34:\"Ce champ a une saisie trop courte.\";s:13:\"upload_failed\";s:72:\"Une erreur inconnue s’est produite lors du téléversement du fichier.\";s:24:\"upload_file_type_invalid\";s:79:\"Vous n’avez pas les droits nécessaires pour téléverser ce type de fichier.\";s:21:\"upload_file_too_large\";s:44:\"Le fichier téléversé est trop volumineux.\";s:23:\"upload_failed_php_error\";s:63:\"Une erreur s’est produite lors du téléversement du fichier.\";s:12:\"invalid_date\";s:46:\"Veuillez saisir une date au format AAAA-MM-JJ.\";s:14:\"date_too_early\";s:34:\"La date de ce champ est trop tôt.\";s:13:\"date_too_late\";s:37:\"La date de ce champ est trop tardive.\";s:14:\"invalid_number\";s:27:\"Veuillez saisir un numéro.\";s:16:\"number_too_small\";s:38:\"Le chiffre de ce champ est trop petit.\";s:16:\"number_too_large\";s:32:\"Ce champ a un numéro trop long.\";s:23:\"quiz_answer_not_correct\";s:42:\"La réponse à la question est incorrecte.\";s:13:\"invalid_email\";s:37:\"Veuillez saisir votre adresse e-mail.\";s:11:\"invalid_url\";s:24:\"Veuillez saisisr une URL\";s:11:\"invalid_tel\";s:42:\"Veuillez saisir un numéro de téléphone.\";}');
