INSERT INTO `wp_posts` VALUES (44,1,'2024-01-16 10:44:16','2024-01-16 10:44:16','<!-- wp:group {\"tagName\":\"section\",\"className\":\"rencontre\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"rencontre\"}} -->\n<section class=\"wp-block-group rencontre\"><!-- wp:image {\"id\":24,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"rencontre-img\"} -->\n<figure class=\"wp-block-image size-full rencontre-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles4.png\" alt=\"\" class=\"wp-image-24\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"rencontre-h2\"} -->\n<h2 class=\"wp-block-heading rencontre-h2\">NOUS RENCONTRER</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"rencontre-p\"} -->\n<p class=\"rencontre-p\">Chez Planty nous sommes tous passionnés par le bien-être, et ça se retrouve dans nos boissons ! Notre start-up s’est construite au fur et à mesure de rencontres entre amoureux des plantes.</p>\n<!-- /wp:paragraph --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"equipe\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"equipe\"}} -->\n<div class=\"wp-block-group equipe\"><!-- wp:heading {\"className\":\"equipe-h3\"} -->\n<h2 class=\"wp-block-heading equipe-h3\">L\'équipe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"id\":21,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"feuilles1bis\"} -->\n<figure class=\"wp-block-image size-full feuilles1bis\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles1.png\" alt=\"\" class=\"wp-image-21\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"membres\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"membres\"}} -->\n<div class=\"wp-block-group membres\"><!-- wp:group {\"tagName\":\"article\",\"className\":\"membre\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"membre\"}} -->\n<article class=\"wp-block-group membre\"><!-- wp:image {\"id\":18,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Equipe1.png\" alt=\"\" class=\"wp-image-18\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"membres-h4\"} -->\n<h2 class=\"wp-block-heading membres-h4\">Mégane</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"membres-p\"} -->\n<p class=\"membres-p\">CEO</p>\n<!-- /wp:paragraph --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"membre\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"membre\"}} -->\n<article class=\"wp-block-group membre\"><!-- wp:image {\"id\":19,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Equipe2.png\" alt=\"\" class=\"wp-image-19\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"membres-h4\"} -->\n<h2 class=\"wp-block-heading membres-h4\">Brooke</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"membres-p\"} -->\n<p class=\"membres-p\">Nutritionniste</p>\n<!-- /wp:paragraph --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"membre\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"membre\"}} -->\n<article class=\"wp-block-group membre\"><!-- wp:image {\"id\":20,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Equipe3.png\" alt=\"\" class=\"wp-image-20\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"membres-h4\"} -->\n<h2 class=\"wp-block-heading membres-h4\">Sylvie</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"membres-p\"} -->\n<p class=\"membres-p\">Mixologue</p>\n<!-- /wp:paragraph --></article>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"nous-contacter\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"nous contacter\"}} -->\n<div class=\"wp-block-group nous-contacter\"><!-- wp:heading {\"className\":\"nous-contacter-h3\"} -->\n<h2 class=\"wp-block-heading nous-contacter-h3\">Nous contacter</h2>\n<!-- /wp:heading -->\n\n<!-- wp:contact-form-7/contact-form-selector {\"id\":259,\"hash\":\"be97d5d\",\"title\":\"contact-form\",\"htmlId\":\"contact-form\",\"htmlName\":\"contactform\",\"htmlTitle\":\"formcontact\",\"htmlClass\":\"form-contact\"} -->\n<div class=\"wp-block-contact-form-7-contact-form-selector\">[contact-form-7 id=\"be97d5d\" title=\"contact-form\" html_id=\"contact-form\" html_name=\"contactform\" html_title=\"formcontact\" html_class=\"form-contact\"]</div>\n<!-- /wp:contact-form-7/contact-form-selector -->\n\n<!-- wp:image {\"id\":23,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"feuilles3\"} -->\n<figure class=\"wp-block-image size-full feuilles3\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles3.png\" alt=\"\" class=\"wp-image-23\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->','Nous rencontrer','','publish','closed','closed','','nous-rencontrer','','','2024-02-05 08:20:27','2024-02-05 08:20:27','',0,'http://planty.local/?page_id=44',0,'page','',0);
