"wp-block-group composition\"><!-- wp:heading {\"className\":\"composition-h3\"} -->\n<h2 class=\"wp-block-heading composition-h3\">L\'énergie des plantes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"composition-p\"} -->\n<p class=\"has-text-align-center composition-p\">Planty, c’est la première boisson énergisante composée à 100 % de produits naturels. Avec son goût frais et fruité, retrouvez votre énergie grâce aux plantes riches en vitamine B2, à n’importe quel moment de la journée.</p>\n<!-- /wp:paragraph --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"className\":\"gouts\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"gouts\"}} -->\n<section class=\"wp-block-group gouts\"><!-- wp:heading {\"className\":\"gouts-h3\"} -->\n<h2 class=\"wp-block-heading gouts-h3\">LES GOÛTS</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"gouts-p\"} -->\n<p class=\"gouts-p\">Nous avons une saveur pour chaque moment de votre journée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"className\":\"fruits\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\"},\"metadata\":{\"name\":\"fruits\"}} -->\n<div class=\"wp-block-group fruits\"><!-- wp:group {\"tagName\":\"article\",\"className\":\"fruits-card\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"fruits card 1\"}} -->\n<article class=\"wp-block-group fruits-card\"><!-- wp:image {\"id\":25,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit1.png\" alt=\"\" class=\"wp-image-25\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"fruits-card-h2\"} -->\n<h2 class=\"wp-block-heading fruits-card-h2\">FRAISE</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"fruits-card\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"fruits card 2\"}} -->\n<div class=\"wp-block-group fruits-card\"><!-- wp:image {\"id\":26,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit2.png\" alt=\"\" class=\"wp-image-26\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"fruits-card-h2\"} -->\n<h2 class=\"wp-block-heading fruits-card-h2\">PAMPLEMOUSSE</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"fruits-card\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"fruits card 3\"}} -->\n<article class=\"wp-block-group fruits-card\"><!-- wp:image {\"id\":27,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit3.png\" alt=\"\" class=\"wp-image-27\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"fruits-card-h2\"} -->\n<h2 class=\"wp-block-heading fruits-card-h2\">FRAMBOISE</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"fruits-card\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"fruits card 4\"}} -->\n<article class=\"wp-block-group fruits-card\"><!-- wp:image {\"id\":28,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit4.png\" alt=\"\" class=\"wp-image-28\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"fruits-card-h2\"} -->\n<h2 class=\"wp-block-heading fruits-card-h2\">CITRON</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:read-more {\"content\":\"Commander\",\"className\":\"gouts-a gouts-a:hover\"} /--></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"avis\"}} -->\n<section class=\"wp-block-group\"><!-- wp:heading {\"className\":\"avis-h2\"} -->\n<h2 class=\"wp-block-heading avis-h2\">CE QU’ILS EN PENSENT</h2>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"temoignages\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoignages\"}} -->\n<div class=\"wp-block-group temoignages\"><!-- wp:group {\"className\":\"temoins\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoins\"}} -->\n<div class=\"wp-block-group temoins\"><!-- wp:image {\"id\":30,\"width\":\"auto\",\"height\":\"139px\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"temoignages-img\"} -->\n<figure class=\"wp-block-image size-full is-resized temoignages-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/P1.png\" alt=\"\" class=\"wp-image-30\" style=\"width:auto;height:139px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"temoin-texte\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"},\"metadata\":{\"name\":\"temoin texte\"}} -->\n<div class=\"wp-block-group temoin-texte\"><!-- wp:heading {\"className\":\"temoin-texte-h3\"} -->\n<h2 class=\"wp-block-heading temoin-texte-h3\">Fatiha</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"temoin-texte-p\"} -->\n<p class=\"temoin-texte-p\">La meilleure boisson énergisante disponible sur le marché !</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"temoins\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoins\"}} -->\n<article class=\"wp-block-group temoins\"><!-- wp:image {\"id\":31,\"width\":\"auto\",\"height\":\"139px\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"temoignages-img\"} -->\n<figure class=\"wp-block-image size-full is-resized temoignages-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/P2.png\" alt=\"\" class=\"wp-image-31\" style=\"width:auto;height:139px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"temoin-texte\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"},\"metadata\":{\"name\":\"temoin texte\"}} -->\n<div class=\"wp-block-group temoin-texte\"><!-- wp:heading {\"className\":\"temoin-texte-h3\"} -->\n<h2 class=\"wp-block-heading temoin-texte-h3\">Véro</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"temoin-texte-p\"} -->\n<p class=\"temoin-texte-p\">Frais &amp; fruité c’est parfait pour accompagner le goûter.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"temoins\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoins\"}} -->\n<article class=\"wp-block-group temoins\"><!-- wp:image {\"id\":32,\"width\":\"auto\",\"height\":\"139px\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"temoignages-img\"} -->\n<figure class=\"wp-block-image size-full is-resized temoignages-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/P3.png\" alt=\"\" class=\"wp-image-32\" style=\"width:auto;height:139px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"temoin-texte\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"},\"metadata\":{\"name\":\"temoin texte\"}} -->\n<div class=\"wp-block-group temoin-texte\"><!-- wp:heading {\"className\":\"temoin-texte-h3\"} -->\n<h2 class=\"wp-block-heading temoin-texte-h3\">Marc</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"temoin-texte-p\"} -->\n<p class=\"temoin-texte-p\">Un boost d’énergie sans produits chimiques, un vrai plus dans ma journée.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></article>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"className\":\"multicans\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"multi canettes\"}} -->\n<section class=\"wp-block-group multicans\"><!-- wp:image {\"id\":34,\"width\":\"150px\",\"height\":\"280px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"style\":{\"layout\":{\"selfStretch\":\"fit\",\"flexSize\":null}},\"className\":\"can1 is-style-default\"} -->\n<figure class=\"wp-block-image size-full is-resized can1 is-style-default\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\" style=\"object-fit:cover;width:150px;height:280px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":34,\"width\":\"150px\",\"height\":\"280px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"style\":{\"layout\":{\"selfStretch\":\"fit\",\"flexSize\":null}},\"className\":\"can2\"} -->\n<figure class=\"wp-block-image size-full is-resized can2\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\" style=\"object-fit:cover;width:150px;height:280px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":34,\"width\":\"150px\",\"height\":\"280px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"can3\"} -->\n<figure class=\"wp-block-image size-full is-resized can3\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\" style=\"obj