izeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"can14\"} -->\n<figure class=\"wp-block-image size-full is-resized can14\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\" style=\"object-fit:cover;width:150px;height:280px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":34,\"width\":\"150px\",\"height\":\"280px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"can15\"} -->\n<figure class=\"wp-block-image size-full is-resized can15\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\" style=\"object-fit:cover;width:150px;height:280px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":34,\"width\":\"150px\",\"height\":\"280px\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"can16\"} -->\n<figure class=\"wp-block-image size-full is-resized can16\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\" style=\"object-fit:cover;width:150px;height:280px\"/></figure>\n<!-- /wp:image --></section>\n<!-- /wp:group -->','multicans','','publish','closed','closed','','multicans','','','2024-01-28 04:16:47','2024-01-28 04:16:47','',0,'http://planty.local/multicans/',0,'wp_block','',0);
INSERT INTO `wp_posts` VALUES (240,1,'2024-01-28 04:17:03','2024-01-28 04:17:03','<!-- wp:group {\"tagName\":\"section\",\"className\":\"presentation\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"presentation\"}} -->\n<section class=\"wp-block-group presentation\"><!-- wp:heading {\"className\":\"slogan\"} -->\n<h2 class=\"wp-block-heading slogan\">BOISSON ÉNERGISANTE </h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"className\":\"slogan\"} -->\n<h2 class=\"wp-block-heading slogan\">100% naturelle</h2>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"plantycan\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"Planty canette\"}} -->\n<div class=\"wp-block-group plantycan\"><!-- wp:image {\"id\":21,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"feuilles1\"} -->\n<figure class=\"wp-block-image size-full feuilles1\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles1.png\" alt=\"\" class=\"wp-image-21\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":34,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"canette\"} -->\n<figure class=\"wp-block-image size-full canette\"><img src=\"http://planty.local/wp-content/uploads/2024/01/PlantyCan.png\" alt=\"\" class=\"wp-image-34\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":22,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"feuilles2\"} -->\n<figure class=\"wp-block-image size-full feuilles2\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles2.png\" alt=\"\" class=\"wp-image-22\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"className\":\"composition\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"composition\"}} -->\n<section class=\"wp-block-group composition\"><!-- wp:heading {\"className\":\"composition-h3\"} -->\n<h2 class=\"wp-block-heading composition-h3\">L\'énergie des plantes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"className\":\"composition-p\"} -->\n<p class=\"has-text-align-center composition-p\">Planty, c’est la première boisson énergisante composée à 100 % de produits naturels. Avec son goût frais et fruité, retrouvez votre énergie grâce aux plantes riches en vitamine B2, à n’importe quel moment de la journée.</p>\n<!-- /wp:paragraph --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"className\":\"gouts\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"gouts\"}} -->\n<section class=\"wp-block-group gouts\"><!-- wp:heading {\"className\":\"gouts-h3\"} -->\n<h2 class=\"wp-block-heading gouts-h3\">LES GOÛTS</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"gouts-p\"} -->\n<p class=\"gouts-p\">Nous avons une saveur pour chaque moment de votre journée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"className\":\"fruits\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\"},\"metadata\":{\"name\":\"fruits\"}} -->\n<div class=\"wp-block-group fruits\"><!-- wp:block {\"ref\":208} /-->\n\n<!-- wp:block {\"ref\":212} /-->\n\n<!-- wp:block {\"ref\":213} /-->\n\n<!-- wp:block {\"ref\":214} /--></div>\n<!-- /wp:group -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|white\"}}}},\"textColor\":\"white\",\"className\":\"gouts-a gouts-a:hover\"} -->\n<h3 class=\"wp-block-heading has-text-align-center gouts-a gouts-a:hover has-white-color has-text-color has-link-color\"><a href=\"http://planty.local/commander/\" data-type=\"page\" data-id=\"46\">Commander</a></h3>\n<!-- /wp:heading --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"avis\"}} -->\n<section class=\"wp-block-group\"><!-- wp:heading {\"className\":\"avis-h2\"} -->\n<h2 class=\"wp-block-heading avis-h2\">CE QU’ILS EN PENSENT</h2>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"temoignages\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoignages\"}} -->\n<div class=\"wp-block-group temoignages\"><!-- wp:group {\"className\":\"temoins\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoins\"}} -->\n<div class=\"wp-block-group temoins\"><!-- wp:image {\"id\":30,\"width\":\"auto\",\"height\":\"139px\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"temoignages-img\"} -->\n<figure class=\"wp-block-image size-full is-resized temoignages-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/P1.png\" alt=\"\" class=\"wp-image-30\" style=\"width:auto;height:139px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"temoin-texte\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"},\"metadata\":{\"name\":\"temoin texte\"}} -->\n<div class=\"wp-block-group temoin-texte\"><!-- wp:heading {\"className\":\"temoin-texte-h3\"} -->\n<h2 class=\"wp-block-heading temoin-texte-h3\">Fatiha</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"temoin-texte-p\"} -->\n<p class=\"temoin-texte-p\">La meilleure boisson énergisante disponible sur le marché !</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"temoins\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoins\"}} -->\n<article class=\"wp-block-group temoins\"><!-- wp:image {\"id\":31,\"width\":\"auto\",\"height\":\"139px\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"temoignages-img\"} -->\n<figure class=\"wp-block-image size-full is-resized temoignages-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/P2.png\" alt=\"\" class=\"wp-image-31\" style=\"width:auto;height:139px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"temoin-texte\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"},\"metadata\":{\"name\":\"temoin texte\"}} -->\n<div class=\"wp-block-group temoin-texte\"><!-- wp:heading {\"className\":\"temoin-texte-h3\"} -->\n<h2 class=\"wp-block-heading temoin-texte-h3\">Véro</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"temoin-texte-p\"} -->\n<p class=\"temoin-texte-p\">Frais &amp; fruité c’est parfait pour accompagner le goûter.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"temoins\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"temoins\"}} -->\n<article class=\"wp-block-group temoins\"><!-- wp:image {\"id\":32,\"width\":\"auto\",\"height\":\"139px\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"temoignages-img\"} -->\n<figure class=\"wp-block-image size-full is-resized temoignages-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/P3.png\" alt=\"\" class=\"wp-image-32\" style=\"width:auto;height:139px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"temoin-texte\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"left\"},\"metadata\":{\"name\":\"temoin texte\"}} -->\n<div class=\"wp-block-group temoin-texte\"><!-- wp:heading {\"className\":\"temoin-texte-h3\"} -->\n<h2 class=\"wp-block-heading temoin-texte-h3\">Marc</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"temoin-texte-p\"} -->\n<p class=\"temoin-texte-p\">Un boost d’énergie sans produits chimiques, un vrai plus dans ma journée.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></article>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->\n\n<!-- wp:block {\"ref\":239} /-->','Home','','inherit','closed','closed','','9-revision-v1','','','2024-01-28 04:17:03','2024-01-28 04:17:03','',9,'http://planty.local/?p=240',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (241,1,'2024-01-28 04:17:48','2024-01-28 04:17:48','<!-- wp:group {\"tagName\":\"section\",\"className\":\"rencontre\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"rencontre\"}} -->\n<section class=\"wp-block-group rencontre\"><!-- wp:image {\"id\":24,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"rencontre-img\"} -->\n<figure class=\"wp-block-image size-full rencontre-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles4.png\" alt=\"\" class=\"wp-image-24\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"rencontre-h2\"} -->\n<h2 class=\"wp-block-heading rencontre-h2\">NOUS RENCONTRER</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"rencontre-p\"} -->\n<p class=\"rencontre-p\">Chez Planty nous sommes tous passionnés par le bien-être, et ça se retrouve dans nos boissons ! Notre start-up s’est construite au fur et à mesure de rencontres entre amoureux des plantes.</p>\n<!-- /wp:paragraph --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"equipe\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"equipe\"}} -->\n<div class=\"wp-block-group equipe\"><!-- wp:heading {\"className\":\"equipe-h3\"} -->\n<h2 class=\"wp-block-heading equipe-h3\">L\'équipe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"id\":21,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"feuilles1bis\"} -->\n<figure class=\"wp-block-image size-full feuilles1bis\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles1.png\" alt=\"\" class=\"wp-image-21\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"membres\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"membres\"}} -->\n<div class=\"wp-block-group membres\"><!-- wp:group {\"tagName\":\"articl