INSERT INTO `wp_posts` VALUES (259,1,'2024-01-28 14:45:03','2024-01-28 14:45:03','<label class=\"form-label\"> Nom\r\n    [text* your-name autocomplete:name] </label>\r\n\r\n<label class=\"form-label\"> E-mail\r\n    [email* your-email autocomplete:email] </label>\r\n\r\n<label class=\"form-label\"> Message\r\n    [textarea your-message] </label>\r\n\r\n<div class=\"submit\">\r\n[submit \"Envoyer\"]\r\n</div>\n1\n[_site_title] \"Formulaire de contact\"\n[_site_title] <wordpress@planty.local>\nplanty.drinks@gmail.com\nDe : [your-name] [your-email]\r\nObjet : Formulaire de contact\r\n\r\nCorps du message :\r\n[your-message]\nReply-To: [your-email]\n\n\n\n\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@planty.local>\n[your-email]\nCorps du message :\r\n[your-message]\r\n\r\n-- \r\nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\nReply-To: [_site_admin_email]\n\n\n\nMerci pour votre message. Il a été envoyé.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nUn ou plusieurs champs contiennent une erreur. Veuillez vérifier et essayer à nouveau.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nVous devez accepter les termes et conditions avant d’envoyer votre message.\nVeuillez renseigner ce champ.\nCe champ a une saisie trop longue.\nCe champ a une saisie trop courte.\nUne erreur inconnue s’est produite lors du téléversement du fichier.\nVous n’avez pas les droits nécessaires pour téléverser ce type de fichier.\nLe fichier téléversé est trop volumineux.\nUne erreur s’est produite lors du téléversement du fichier.\nVeuillez saisir une date au format AAAA-MM-JJ.\nLa date de ce champ est trop tôt.\nLa date de ce champ est trop tardive.\nVeuillez saisir un numéro.\nLe chiffre de ce champ est trop petit.\nCe champ a un numéro trop long.\nLa réponse à la question est incorrecte.\nVeuillez saisir votre adresse e-mail.\nVeuillez saisisr une URL\nVeuillez saisir un numéro de téléphone.','contact-form','','publish','closed','closed','','comande-form','','','2024-02-05 09:15:03','2024-02-05 09:15:03','',0,'http://planty.local/?post_type=wpcf7_contact_form&#038;p=259',0,'wpcf7_contact_form','',0);
INSERT INTO `wp_posts` VALUES (264,1,'2024-01-28 19:11:58','2024-01-28 19:11:58','<!-- wp:group {\"tagName\":\"section\",\"className\":\"rencontre\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"rencontre\"}} -->\n<section class=\"wp-block-group rencontre\"><!-- wp:image {\"id\":24,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"rencontre-img\"} -->\n<figure class=\"wp-block-image size-full rencontre-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles4.png\" alt=\"\" class=\"wp-image-24\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"rencontre-h2\"} -->\n<h2 class=\"wp-block-heading rencontre-h2\">NOUS RENCONTRER</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"rencontre-p\"} -->\n<p class=\"rencontre-p\">Chez Planty nous sommes tous passionnés par le bien-être, et ça se retrouve dans nos boissons ! Notre start-up s’est construite au fur et à mesure de rencontres entre amoureux des plantes.</p>\n<!-- /wp:paragraph --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"equipe\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"equipe\"}} -->\n<div class=\"wp-block-group equipe\"><!-- wp:heading {\"className\":\"equipe-h3\"} -->\n<h2 class=\"wp-block-heading equipe-h3\">L\'équipe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"id\":21,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"feuilles1bis\"} -->\n<figure class=\"wp-block-image size-full feuilles1bis\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Feuilles1.png\" alt=\"\" class=\"wp-image-21\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {\"className\":\"membres\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"membres\"}} -->\n<div class=\"wp-block-group membres\"><!-- wp:group {\"tagName\":\"articl