INSERT INTO `wp_posts` VALUES (276,1,'2024-01-28 22:43:01','2024-01-28 22:43:01','<!-- wp:group {\"tagName\":\"section\",\"className\":\"commander\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"commander\"}} -->\n<section class=\"wp-block-group commander\"><!-- wp:heading {\"className\":\"commander-h2\"} -->\n<h2 class=\"wp-block-heading commander-h2\">COMMANDER</h2>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"commande\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"commande\"}} -->\n<div class=\"wp-block-group commande\"><!-- wp:heading {\"style\":{\"layout\":{\"selfStretch\":\"fit\",\"flexSize\":null}},\"className\":\"commande-h3\"} -->\n<h2 class=\"wp-block-heading commande-h3\">Votre commande</h2>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"parfums\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"parfums\"}} -->\n<div class=\"wp-block-group parfums\"><!-- wp:group {\"tagName\":\"article\",\"className\":\"parfum\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"parfum\"}} -->\n<article class=\"wp-block-group parfum\"><!-- wp:image {\"id\":25,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"parfum-img\"} -->\n<figure class=\"wp-block-image size-full parfum-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit1.png\" alt=\"\" class=\"wp-image-25\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"parfum-h2\"} -->\n<h2 class=\"wp-block-heading parfum-h2\">FRAISE</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"parfum\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"parfum\"}} -->\n<article class=\"wp-block-group parfum\"><!-- wp:image {\"id\":26,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"parfum-img\"} -->\n<figure class=\"wp-block-image size-full parfum-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit2.png\" alt=\"\" class=\"wp-image-26\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"parfum-h2\"} -->\n<h2 class=\"wp-block-heading parfum-h2\">PAMPLE<br>MOUSSE</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"parfum\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"parfum\"}} -->\n<article class=\"wp-block-group parfum\"><!-- wp:image {\"id\":27,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"parfum-img\"} -->\n<figure class=\"wp-block-image size-full parfum-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit3.png\" alt=\"\" class=\"wp-image-27\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"parfum-h2\"} -->\n<h2 class=\"wp-block-heading parfum-h2\">FRAM<br>BOISE</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"article\",\"className\":\"parfum\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\",\"justifyContent\":\"center\"},\"metadata\":{\"name\":\"parfum\"}} -->\n<article class=\"wp-block-group parfum\"><!-- wp:image {\"id\":28,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"parfum-img\"} -->\n<figure class=\"wp-block-image size-full parfum-img\"><img src=\"http://planty.local/wp-content/uploads/2024/01/Fruit4.png\" alt=\"\" class=\"wp-image-28\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"className\":\"parfum-h2\"} -->\n<h2 class=\"wp-block-heading parfum-h2\">CITRON</h2>\n<!-- /wp:heading --></article>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->','Commander','','inherit','