INSERT INTO `wp_posts` VALUES (277,1,'2024-01-29 09:18:20','2024-01-29 09:18:20','<div class=\"commande\">\r\n    <h3 class=\"commande-h3\">Votre commande</h3>\r\n\r\n        <div class=\"parfums\">\r\n            <article class=\"parfum\">\r\n                <img class=\"parfum-img\" src=\"http://planty.local/wp-content/uploads/2024/01/Fruit1.png\" alt=\"parfum fraise\">\r\n                <h2 class=\"parfum-h2\">FRAISE</h2>\r\n                [number fraisenb min:0 class:fruitnb placeholder \"0\"]\r\n            </article>\r\n            <article class=\"parfum\">\r\n                <img class=\"parfum-img\" src=\"http://planty.local/wp-content/uploads/2024/01/Fruit2.png\" alt=\"parfum pamplemousse\">\r\n                <h2 class=\"parfum-h2\">PAMPLE<br>MOUSSE</h2>\r\n                [number pamplemoussenb min:0 class:fruitnb placeholder \"0\"]\r\n            </article>\r\n            <article class=\"parfum\">\r\n                <img class=\"parfum-img\" src=\"http://planty.local/wp-content/uploads/2024/01/Fruit3.png\" alt=\"parfum framboise\">\r\n                <h2 class=\"parfum-h2\">FRAM<br>BOISE</h2>\r\n                [number framboisenb min:0 class:fruitnb placeholder \"0\"]\r\n            </article>\r\n            <article class=\"parfum\">\r\n                <img class=\"parfum-img\" src=\"http://planty.local/wp-content/uploads/2024/01/Fruit4.png\" alt=\"parfum citron\">\r\n                <h2 class=\"parfum-h2\">CITRON</h2>\r\n                [number citronnb min:0 class:fruitnb placeholder \"0\"]\r\n            </article> \r\n        </div>\r\n</div>\r\n<div class=\"commande2\">\r\n    <div class=\"commande2a\">\r\n        <h3 class=\"commande-h3\">Vos informations</h3>\r\n        <label class=\"commande-p\"> Nom\r\n            [text* your-name autocomplete:family-name] </label>\r\n        \r\n        <label class=\"commande-p\"> Prénom\r\n            [text* your-first-name autocomplete:given-name] </label>\r\n\r\n        <label class=\"commande-p\"> E-mail\r\n            [email* your-email autocomplete:email] </label>\r\n    </div>\r\n    <div class=\"commande2b\"></div>        \r\n    <div class=\"commande2c\">\r\n         <h3 class=\"commande-h3\">Livraison</h3>\r\n         <label class=\"commande-p\"> Adresse de livraison\r\n               [text* your-adress autocomplete:address-level1] </label>\r\n\r\n         <label class=\"commande-p\"> Code postal\r\n               [text* your-postal-code autocomplete:postal-code] </label>\r\n     \r\n         <label class=\"commande-p\"> Ville\r\n               [text* your-city autocomplete:address-level2] </label>\r\n     </div>\r\n</div>                                    \r\n<div class=\"submit-commander\">\r\n[submit \"Commander\"]\r\n</div>\n1\n[_site_title] \"Formulaire de précommande\"\n[_site_title] <wordpress@planty.local>\nplanty.drinks@gmail.com\nDe : [your-name] [your-email]\r\nObjet : Formulaire de précommande\r\n\r\nCorps du message :\r\n\r\nQuantités demandées\r\nFraise: [fraisenb]\r\nPamplemousse: [pamplemoussenb]\r\nFramboise: [framboisenb]\r\nCitron: [citronnb]\r\n\r\nInformation de l\'acheteur\r\n[your-name][your-first-name]\r\n[your-email]\r\n[your-adress]\r\n[your-postal-code][your-city]\nReply-To: [your-email]\n\n\n\n\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@planty.local>\n[your-email]\nCorps du message :\r\n[your-message]\r\n\r\n-- \r\nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\nReply-To: [_site_admin_email]\n\n\n\nMerci pour votre message. Il a été envoyé.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nUn ou plusieurs champs contiennent une erreur. Veuillez vérifier et essayer à nouveau.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nVous devez accepter les termes et conditions avant d’envoyer votre message.\nVeuillez renseigner ce champ.\nCe champ a une saisie trop longue.\nCe champ a une saisie trop courte.\nUne erreur inconnue s’est produite lors du téléversement du fichier.\nVous n’avez pas les droits nécessaires pour téléverser ce type de fichier.\nLe fichier téléversé est trop volumineux.\nUne erreur s’est produite lors du téléversement du fichier.\nVeuillez saisir une date au format AAAA-MM-JJ.\nLa date de ce champ est trop tôt.\nLa date de ce champ est trop tardive.\nVeuillez saisir un numéro.\nLe chiffre de ce champ est trop petit.\nCe champ a un numéro trop long.\nLa réponse à la question est incorrecte.\nVeuillez saisir votre adresse e-mail.\nVeuillez saisisr une URL\nVeuillez saisir un numéro de téléphone.','commande-form','','publish','closed','closed','','sans-titre','','','2024-02-05 09:44:50','2024-02-05 09:44:50','',0,'http://planty.local/?post_type=wpcf7_contact_form&#038;p=277',0,'wpcf7_contact_form','',0);
